    [
      g._$k, g._$u, g._$t, g._getItemValue(r, g._$cSite), g._getItemValue(r, g._$cSiteName), g._getItemValue(r, g._$cItem), g._getItemValue(r, g._$cItemName),
      g._getItemValue(r, g._$cLocation), g._getItemValue(r, g._$cLocationName), g._getItemValue(r, g._$cLot), g._getItemValue(r, g._$cLotName),
      g._getItemValue(r, g._$cVarQty), g._getItemValue(r, g._$cLocation), g._getItemValue(r, g._$cLot),
      g._getItemValue(r, g._getColumnOrder('gia')), g._getItemValue(r, g._getColumnOrder('tien')),g._getItemValue(r, g._getColumnOrder('pn_gia_tb')), g._getItemValue(r, g._getColumnOrder('px_gia_dd')),
      g._getItemValue(r, g._getColumnOrder('ma_vi_tri')), g._getItemValue(r, g._getColumnOrder('ma_lo'))
    ]);
  f.setReadOnlyFields('ma_kho, ma_vt, sl_cl');

  if (vi_tri_yn) f.setReferenceKeyFilter('ma_vi_tri_x');
  if (l_yn) f.setReferenceKeyFilter('ma_lo_x');

  for (var i = 0; i < fReadOnly.length; i++) setItemReadOnly(f, fReadOnly[i], vReadOnly[i]);
  for (var j = 0; j < fReadOnly.length; j++) {
    var o = f.getItem(fReadOnly[j]);
    if (!o.disabled) {
      o.focus();
      break;
    } else u.focus();
  }
}
function close$AutoGenerateStocktakingUpdate$(f) {f.$a = null;}
