function setItemReadOnly(f, c, v) {
  var o = f.getItem(c);
  o.disabled = !v;
  if (o.a) $common.setVisible(o.a, v);
  if ('ma_vi_tri_x,ma_lo_x'.indexOf(c) != -1) setItemAllowNulls(f, c, v);
}
