}
function show$AutoGenerateStocktakingUpdate$QueryComplete(g, v1, v2, v3, v4, v5, v6) {
  g._setItemValue(g._activeRow, g._getColumnOrder('ma_vi_tri_x'), v1);
  g._setItemValue(g._activeRow, g._getColumnOrder('ma_lo_x'), v2);
  g._setItemValue(g._activeRow, g._getColumnOrder('pn_gia_tb'), (v3 == 1 ? true : false));
  g._setItemValue(g._activeRow, g._getColumnOrder('px_gia_dd'), (v4 == 1 ? true : false));
  g._setItemValue(g._activeRow, g._getColumnOrder('gia'), v5);
  g._setItemValue(g._activeRow, g._getColumnOrder('tien'), v6);
  g._focusWhenTabChanged();
}
function setItemAllowNulls(f, c, v) {
  var a = c.split(','), o, grandNode;
  for (var i = 0; i < a.length; i++) {
    if ($func.trim(a[i]) != '') {
      o = f.getItem($func.trim(a[i]));
      o.field.AllowNulls = !v
      grandNode = o.parentNode.parentNode;
      if (v) {
        Sys.UI.DomElement.addCssClass(grandNode, 'Required');
        Sys.UI.DomElement.addCssClass(grandNode, f._id);
      }
      else Sys.UI.DomElement.removeCssClass(grandNode, 'Required');
